from typing import List, Dict, Any, Optional
from leann.api import PassageManager
from pathlib import Path
import json


def filter_passages_by_metadata_criteria(
    index_path: str,
    metadata_criteria: Dict[str, Any]
) -> List[Dict[str, Any]]:
    """Retrieve all passages from an index that match metadata criteria.

    Args:
        index_path: Path to the LEANN index file
        metadata_criteria: Dictionary of metadata field-value pairs to match.
            Example: {"category": "tech", "rating": 5.0}
            All criteria must match (AND logic)

    Returns:
        List of passage dictionaries that match all criteria

    Raises:
        FileNotFoundError: If index metadata file is not found
    """
    try:
        # Initialize PassageManager with the index path
        passage_manager = PassageManager(index_path)

        # Get all passage IDs from the index
        passage_ids = list(passage_manager.offset_map.keys())

        if not passage_ids:
            return []

        # Create a list of search results with metadata for filtering
        search_results = []
        for passage_id in passage_ids:
            try:
                passage_data = passage_manager.get_passage(passage_id)
                search_results.append({
                    'id': passage_id,
                    'metadata': passage_data.get('metadata', {})
                })
            except KeyError:
                continue  # Skip if passage can't be retrieved

        # Convert metadata criteria to the format expected by filter_search_results
        metadata_filters = {}
        for field, value in metadata_criteria.items():
            metadata_filters[field] = {"==": value}

        # Apply metadata filters using PassageManager's filter_search_results method
        filtered_results = passage_manager.filter_search_results(search_results, metadata_filters)

        # Convert filtered search results back to full passage dictionaries
        filtered_passages = []
        for result in filtered_results:
            try:
                passage_data = passage_manager.get_passage(result['id'])
                filtered_passages.append(passage_data)
            except KeyError:
                continue  # Skip if passage can't be retrieved after filtering

        return filtered_passages

    except FileNotFoundError as e:
        # Re-raise with appropriate message
        raise FileNotFoundError(f"Index metadata file not found: {index_path}") from e

